{"command": "cat > test_final.py << 'EOF'
import sqlfluff

test_cases = [
    # (description, query, should_have_l031)
    ("Simple query with alias", "SELECT a.[hello] FROM mytable AS a", True),
    ("Simple query without alias", "SELECT [hello] FROM mytable", False),
    ("Query with join and aliases", "SELECT a.[hello], b.[world] FROM mytable AS a JOIN othertable AS b ON a.id = b.id", True),
    ("Query with join but no aliases", "SELECT mytable.[hello], othertable.[world] FROM mytable JOIN othertable ON mytable.id = othertable.id", False),
    ("Self-join with alias", "SELECT t1.col, t2.col FROM mytable AS t1 JOIN mytable AS t2 ON t1.id = t2.parent_id", False),  # Self-joins should not trigger L031
    ("Alias not used in select", "SELECT [hello] FROM mytable AS a", True),  # Still triggers because alias exists
]

print("Testing L031 with updated error message:\n")
for desc, query, should_have_l031 in test_cases:
    print(f"Test: {desc}")
    print(f"Query: {query}")
    result = sqlfluff.lint(query, dialect="tsql")
    l031_results = [r for r in result if r['code'] == 'L031']

    if should_have_l031:
        if l031_results:
            print(f"✓ L031 triggered as expected: {l031_results[0]['description']}")
        else:
            print(f"✗ L031 NOT triggered but should have been")
    else:
        if l031_results:
            print(f"✗ L031 triggered but should NOT have been: {l031_results[0]['description']}")
        else:
            print(f"✓ L031 not triggered as expected")
    print()
EOF

python test_final.py"}

